export async function handleOwnerDashboardRequest(request: Request): Promise<Response> {
  const authError = await requireOwner(request);
  if (authError) return authError;
  // Import existing deal/investor summaries lazily to avoid circular deps.
  const { summarizeDeals } = await import('../services/ivx-deal-tracking-store');
  const { summarizeInvestors } = await import('../services/ivx-investor-crm-store');
  const dealSummaryRaw = await summarizeDeals();
  const investorSummaryRaw = await summarizeInvestors();
  const dealSummary = {
    count: dealSummaryRaw.total ?? 0,
    active: (dealSummaryRaw as Record<string, unknown>).activeCount as number ?? 0,
    closedWon: (dealSummaryRaw as Record<string, unknown>).closedWon as number ?? 0,
    closedLost: (dealSummaryRaw as Record<string, unknown>).closedLost as number ?? 0,
  };
  const investorSummary = {
    count: investorSummaryRaw.total ?? 0,
    active: (investorSummaryRaw as Record<string, unknown>).activeCount as number ?? 0,
    invested: (investorSummaryRaw as Record<string, unknown>).investedCount as number ?? 0,
  };
  const summary = await getOwnerDashboardSummary(dealSummary, investorSummary);
  return ownerOnlyJson({ ok: true, dashboard: summary });
}

